/*
  # Seed Get Started sidebar groups and pages

  Creates 5 sidebar groups with ~30 child topic pages for the
  Get Started section. Organized by deployment role: counties,
  agencies, frontline workers, and compliance reporting.
*/

DO $$
DECLARE
  v_section_id uuid;
  v_group_id uuid;
BEGIN
  SELECT id INTO v_section_id FROM nav_sections WHERE slug = 'get-started';

  -- Group 1: Before You Begin
  VALUES (v_section_id, 'Before You Begin', 'before-you-begin', 1)
  RETURNING id INTO v_group_id;

   'A decision framework for evaluating whether CivikStack fits your needs.',
   '<h2 id="right-for-you">Is CivikStack right for your situation</h2><p>CivikStack is designed for counties and agencies that deliver civic services to residents and want to measure whether those services actually work. If your organization operates service pathways — sequences of steps that residents follow to access housing, benefits, healthcare, workforce, or other civic services — CivikStack can measure whether those pathways are working as designed.</p><p>CivikStack is not a case management system, a benefits eligibility engine, or a program management tool. It is measurement infrastructure that sits alongside your existing systems and provides access reliability data that your existing systems cannot generate.</p>'),
  (v_group_id, 'What you will need', 'what-you-will-need', 2,
   'Technical and organizational prerequisites for deploying CivikStack.',
   '<h2 id="what-you-need">What you will need</h2><p>Deploying CivikStack requires three things: infrastructure capacity appropriate to your scale tier, staff capacity to configure and maintain the deployment, and organizational commitment to act on the access reliability data the system produces. The infrastructure requirements range from a single desktop for evaluation to a Kubernetes cluster for county production.</p>'),
  (v_group_id, 'The deployment decision checklist', 'the-deployment-decision-checklist', 3,
   'A structured checklist for making the deployment decision.',
   '<h2 id="decision-checklist">The deployment decision checklist</h2><p>Before deploying CivikStack, work through this checklist with your leadership team: Have you identified the service pathways you want to measure? Do you have the infrastructure capacity for your chosen scale tier? Do you have staff who can configure and maintain the deployment? Do you have organizational commitment to act on access reliability findings? Have you identified the compliance reporting requirements you want to automate?</p>');

  -- Group 2: For Counties — Deploying CivikGrid
  VALUES (v_section_id, 'For Counties — Deploying CivikGrid', 'for-counties-deploying-civikgrid', 2)
  RETURNING id INTO v_group_id;


  -- Group 3: For Agencies — Adopting a Vertical
  VALUES (v_section_id, 'For Agencies — Adopting a Vertical', 'for-agencies-adopting-a-vertical', 3)
  RETURNING id INTO v_group_id;


  -- Group 4: For Frontline Workers
  VALUES (v_section_id, 'For Frontline Workers', 'for-frontline-workers', 4)
  RETURNING id INTO v_group_id;


  -- Group 5: Compliance Reporting
  VALUES (v_section_id, 'Compliance Reporting — Getting Your First Report', 'compliance-reporting-getting-your-first-report', 5)
  RETURNING id INTO v_group_id;


END $$;
